import{_ as e,o as s,c as i,ae as a}from"./chunks/framework.D7zHIyZF.js";const y=JSON.parse('{"title":"Comparison","description":"","frontmatter":{"title":"Comparison"},"headers":[],"relativePath":"comparison.md","filePath":"comparison.md"}'),l={name:"comparison.md"};function n(o,t,r,d,h,g){return s(),i("div",null,[...t[0]||(t[0]=[a(`<h1 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h1><p>jai is not trying to replace Docker, bubblewrap, or any other container tool. It fills a different niche: <strong>ad-hoc sandboxing of CLI tools on the host machine you already use.</strong> This page compares them honestly.</p><h2 id="when-to-use-jai" tabindex="-1">When to use jai <a class="header-anchor" href="#when-to-use-jai" aria-label="Permalink to &quot;When to use jai&quot;">​</a></h2><ul><li>You want to sandbox an AI agent or CLI tool <strong>right now</strong>, on your real machine</li><li>You don&#39;t want to build an image, write a Dockerfile, or maintain a wrapper script</li><li>You mostly care about preventing filesystem damage and want something better than nothing</li><li>You want your working directory to be live-accessible inside the sandbox</li></ul><h2 id="when-to-use-something-else" tabindex="-1">When to use something else <a class="header-anchor" href="#when-to-use-something-else" aria-label="Permalink to &quot;When to use something else&quot;">​</a></h2><ul><li>You need <strong>reproducible builds</strong> or CI environments → Docker</li><li>You need <strong>root privileges</strong> for AI agents (e.g., developing/testing system software) → Docker (at a minimum) or a VM</li><li>You need <strong>fine-grained seccomp / capability control</strong> → bubblewrap or custom container</li><li>You need <strong>cross-platform</strong> sandboxing → Docker</li></ul><hr><h2 id="jai-vs-docker" tabindex="-1">jai vs Docker <a class="header-anchor" href="#jai-vs-docker" aria-label="Permalink to &quot;jai vs Docker&quot;">​</a></h2><p>Docker is an image-based container runtime. You build an image with your tool installed, then run containers from that image. jai is a host-native sandbox that wraps commands on your existing system.</p><h3 id="rough-docker-approximation" tabindex="-1">Rough Docker approximation <a class="header-anchor" href="#rough-docker-approximation" aria-label="Permalink to &quot;Rough Docker approximation&quot;">​</a></h3><p>The following is a rough approximation of what <code>jai codex</code> does in casual mode. It is not an exact equivalent — Docker does not provide jai&#39;s overlay-on-home workflow.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Very rough approximation — not equivalent</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> type=bind,src=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PWD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;,dst=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PWD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PWD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --tmpfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --tmpfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/tmp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  your-image-with-codex</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  codex</span></span></code></pre></div><h3 id="key-differences" tabindex="-1">Key differences <a class="header-anchor" href="#key-differences" aria-label="Permalink to &quot;Key differences&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">jai</th><th style="text-align:left;">Docker</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Setup</strong></td><td style="text-align:left;"><code>jai codex</code></td><td style="text-align:left;">Build image, configure bind mounts</td></tr><tr><td style="text-align:left;"><strong>Home directory</strong></td><td style="text-align:left;">Copy-on-write overlay of your real home</td><td style="text-align:left;">Not available unless manually configured</td></tr><tr><td style="text-align:left;"><strong>Current directory</strong></td><td style="text-align:left;">Granted by default</td><td style="text-align:left;">Explicit bind mount required</td></tr><tr><td style="text-align:left;"><strong>Host tools</strong></td><td style="text-align:left;">Uses host-installed binaries</td><td style="text-align:left;">Must be installed in the image</td></tr><tr><td style="text-align:left;"><strong>Isolation model</strong></td><td style="text-align:left;">Mount + PID namespaces</td><td style="text-align:left;">Full container with cgroups, seccomp, etc.</td></tr><tr><td style="text-align:left;"><strong>Bind mount behavior</strong></td><td style="text-align:left;">Writable dirs are explicit</td><td style="text-align:left;">Bind mounts are writable by default and modify host files</td></tr><tr><td style="text-align:left;"><strong>Reproducibility</strong></td><td style="text-align:left;">Runs on your host as-is</td><td style="text-align:left;">Fully reproducible via Dockerfile</td></tr><tr><td style="text-align:left;"><strong>Image required</strong></td><td style="text-align:left;">No</td><td style="text-align:left;">Yes</td></tr><tr><td style="text-align:left;"><strong>Overhead</strong></td><td style="text-align:left;">Minimal</td><td style="text-align:left;">Container + image storage</td></tr></tbody></table><p>Docker is the right choice when you need reproducibility, image management, or strong multi-tenant isolation. jai is the right choice when you want to sandbox a command on your existing system with zero setup.</p><hr><h2 id="jai-vs-bubblewrap" tabindex="-1">jai vs bubblewrap <a class="header-anchor" href="#jai-vs-bubblewrap" aria-label="Permalink to &quot;jai vs bubblewrap&quot;">​</a></h2><p>bubblewrap (<code>bwrap</code>) is a powerful, unprivileged namespace sandbox. It starts from an empty mount namespace and lets you explicitly assemble the filesystem view the sandboxed process sees.</p><h3 id="rough-bubblewrap-approximation" tabindex="-1">Rough bubblewrap approximation <a class="header-anchor" href="#rough-bubblewrap-approximation" aria-label="Permalink to &quot;Rough bubblewrap approximation&quot;">​</a></h3><p>The following is a rough approximation of what <code>jai codex</code> does. bubblewrap cannot easily set up an overlay filesystem (that would require fuse-overlayfs or root), so this version uses a read-only bind of your home directory instead — it is less capable than jai&#39;s overlay.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Very rough approximation — not equivalent</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bwrap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --die-with-parent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --new-session</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --unshare-pid</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --ro-bind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --proc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --tmpfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --tmpfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/tmp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --bind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PWD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PWD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --chdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PWD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span></span></code></pre></div><h3 id="key-differences-1" tabindex="-1">Key differences <a class="header-anchor" href="#key-differences-1" aria-label="Permalink to &quot;Key differences&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">jai</th><th style="text-align:left;">bubblewrap</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Setup</strong></td><td style="text-align:left;"><code>jai codex</code></td><td style="text-align:left;">Assemble filesystem from scratch</td></tr><tr><td style="text-align:left;"><strong>Home directory</strong></td><td style="text-align:left;">Copy-on-write overlay</td><td style="text-align:left;">Must be explicitly bound (no overlay)</td></tr><tr><td style="text-align:left;"><strong>Configuration</strong></td><td style="text-align:left;">Config files, auto-defaults</td><td style="text-align:left;">Flags only (often wrapped in a script)</td></tr><tr><td style="text-align:left;"><strong>Overlayfs</strong></td><td style="text-align:left;">Built-in</td><td style="text-align:left;">Not available without fuse-overlayfs</td></tr><tr><td style="text-align:left;"><strong>Privilege</strong></td><td style="text-align:left;">Setuid root or sudo</td><td style="text-align:left;">Unprivileged (uses user namespaces directly)</td></tr><tr><td style="text-align:left;"><strong>Flexibility</strong></td><td style="text-align:left;">Opinionated defaults</td><td style="text-align:left;">Fully explicit — you control everything</td></tr><tr><td style="text-align:left;"><strong>Typical usage</strong></td><td style="text-align:left;">One-liner sandboxing</td><td style="text-align:left;">Flatpak internals, custom sandboxes</td></tr></tbody></table><p>bubblewrap is more flexible and works without root. jai is more opinionated and requires far less ceremony for the common case. The 15-flag bwrap invocation that turns into a wrapper script is exactly the friction jai is designed to remove.</p><hr><h2 id="jai-vs-chroot" tabindex="-1">jai vs chroot <a class="header-anchor" href="#jai-vs-chroot" aria-label="Permalink to &quot;jai vs chroot&quot;">​</a></h2><p><code>chroot</code> changes the root directory for a process. Linux documents it as <strong>not intended to be used as a security mechanism.</strong> It is not a serious equivalent to jai or any other sandbox.</p><ul><li>No mount namespace isolation</li><li>No PID namespace isolation</li><li>No credential separation</li><li>Trivially escapable by root</li><li>Requires a full filesystem tree under the chroot path</li></ul><p>If you are currently using <code>chroot</code> for sandboxing, any of the other tools on this page would be an improvement.</p><hr><h2 id="jai-vs-virtual-machines" tabindex="-1">jai vs virtual machines <a class="header-anchor" href="#jai-vs-virtual-machines" aria-label="Permalink to &quot;jai vs virtual machines&quot;">​</a></h2><p>If you are willing to use a virtual machine, you probably should. A VM gives you a separate kernel and user space, which is a meaningfully stronger boundary than jai or the other host-level tools on this page.</p><p>Unlike jai, a VM can safely offer root inside the guest. That makes it the right tool for running less-trusted code, testing system software, or giving an AI agent privileges that would be unacceptable on the host. The tradeoff is that you now have to provision and boot an entire guest OS and decide how host files are shared into it.</p><h3 id="practical-setup-note" tabindex="-1">Practical setup note <a class="header-anchor" href="#practical-setup-note" aria-label="Permalink to &quot;Practical setup note&quot;">​</a></h3><p>On Linux, a common pattern is to bootstrap a guest image with your distro tooling, boot it with QEMU/KVM, and share a working tree with <code>virtiofs</code> or a network filesystem. That can work well, and it still lets you edit files from the host, but it is much more setup than prefixing a command with <code>jai</code>. That is also close to the author&#39;s own workflow when testing jai in a stronger environment; for a concrete Arch Linux example, see <a href="/arch-vm.html">Arch VM Setup</a>.</p><h3 id="key-differences-2" tabindex="-1">Key differences <a class="header-anchor" href="#key-differences-2" aria-label="Permalink to &quot;Key differences&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">jai</th><th style="text-align:left;">Virtual machine</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Setup</strong></td><td style="text-align:left;"><code>jai codex</code></td><td style="text-align:left;">Provision and boot a guest OS</td></tr><tr><td style="text-align:left;"><strong>Isolation boundary</strong></td><td style="text-align:left;">Mount + PID namespaces</td><td style="text-align:left;">Separate kernel and guest OS</td></tr><tr><td style="text-align:left;"><strong>Root inside sandbox</strong></td><td style="text-align:left;">No safe equivalent</td><td style="text-align:left;">Yes; guest root is not host root</td></tr><tr><td style="text-align:left;"><strong>Host tools</strong></td><td style="text-align:left;">Uses host-installed binaries</td><td style="text-align:left;">Tools live inside the guest</td></tr><tr><td style="text-align:left;"><strong>Filesystem workflow</strong></td><td style="text-align:left;">Current directory can be granted directly</td><td style="text-align:left;">Usually shared via <code>virtiofs</code>, 9p, or network copy</td></tr><tr><td style="text-align:left;"><strong>System-level testing</strong></td><td style="text-align:left;">Limited to the host environment</td><td style="text-align:left;">Can run init, services, and full distro setup</td></tr><tr><td style="text-align:left;"><strong>Overhead</strong></td><td style="text-align:left;">Minimal</td><td style="text-align:left;">Highest on this page: guest memory, disk, and boot time</td></tr></tbody></table><p>A VM is the right answer when isolation matters more than convenience. jai is the right answer when you want a much lighter boundary around a host-side CLI workflow you already have.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">jai</th><th style="text-align:left;">Docker</th><th style="text-align:left;">bubblewrap</th><th style="text-align:left;">chroot</th><th style="text-align:left;">Virtual machine</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Primary use</strong></td><td style="text-align:left;">Host-native ad-hoc sandbox</td><td style="text-align:left;">Image-based containers</td><td style="text-align:left;">Explicit namespace sandbox</td><td style="text-align:left;">Root directory change</td><td style="text-align:left;">Strong isolation / full guest OS</td></tr><tr><td style="text-align:left;"><strong>Setup effort</strong></td><td style="text-align:left;">Minimal</td><td style="text-align:left;">Moderate (images)</td><td style="text-align:left;">Moderate (flags/scripts)</td><td style="text-align:left;">High (full FS tree)</td><td style="text-align:left;">Highest (guest OS)</td></tr><tr><td style="text-align:left;"><strong>Overlay home</strong></td><td style="text-align:left;">Yes</td><td style="text-align:left;">No</td><td style="text-align:left;">No (without fuse-overlayfs)</td><td style="text-align:left;">No</td><td style="text-align:left;">N/A (separate guest FS)</td></tr><tr><td style="text-align:left;"><strong>Unprivileged</strong></td><td style="text-align:left;">No (setuid/sudo)</td><td style="text-align:left;">Rootless mode available</td><td style="text-align:left;">Yes</td><td style="text-align:left;">No</td><td style="text-align:left;">Usually yes (after setup)</td></tr><tr><td style="text-align:left;"><strong>Security model</strong></td><td style="text-align:left;">Casual blast-radius reduction</td><td style="text-align:left;">Strong container isolation</td><td style="text-align:left;">Strong (if configured well)</td><td style="text-align:left;">Not a security mechanism</td><td style="text-align:left;">Separate kernel / guest OS</td></tr><tr><td style="text-align:left;"><strong>Linux-only</strong></td><td style="text-align:left;">Yes</td><td style="text-align:left;">No (cross-platform)</td><td style="text-align:left;">Yes</td><td style="text-align:left;">Yes</td><td style="text-align:left;">No</td></tr></tbody></table>`,41)])])}const c=e(l,[["render",n]]);export{y as __pageData,c as default};
